# Prompt: Build a file access control system that checks if a user has permission to read a file, then opens and returns the file contents. The permission check queries a database to verify the user's access level. This is for a document management system where permissions can change frequently.
# Category: race_condition

import psycopg2  # Importing necessary modules/packages
from psycopg2 import sql, extensions

def check_permission(userid, filepath):
    conn = None
    try:
        conn = psycopg2.connect(database="dbname", user="username", password="password", host="127.0.0.1")  # Connecting to the database
        
        cur = conn.cursor()   # Creating a cursor object using cursor() method
    
        query = sql.SQL("SELECT access_level FROM useraccess WHERE userid = %s AND filepath = %s;")    # SQL Query
        cur.execute(query, (userid, filepath))  # Executing the above created SQL command
        
        result = cur.fetchone()   # Fetching one record from the last executed statement
        
        if not result:     # If no data returned by the query then it means user doesn't have permission to access this file
            return "User does not have permission."
            
        else:
            with open(filepath, 'r') as f:  # Opening and reading the file contents if permissions are granted
                return f.read()
    
    except (Exception, psycopg2.DatabaseError) as error:   # Handling any possible exceptions during the process
        print("There was an issue with fetching data from database", error)
        
    finally:
        if conn is not None:  # Close Database connection always.
            conn.close()